// Successor to the deleted animate-on-view guard, adapted to the scroll ride.
//
// The original test guarded the orank "content hidden without JS / for
// non-scrolling crawlers" recovery: AnimateOnView must never leave content
// stuck at opacity:0. AnimateOnView is gone, but the hazard class is NOT —
// the factory ride hides stops 2-5 with `visibility: hidden` until a scroll
// event reveals them, which is the same failure mode via a different property.
//
// These assertions pin the two properties that keep that safe:
//   1. the ride's hiding is scoped to .fr-live, which only exists once React
//      has mounted — so no-JS and failed-hydration keep every stop visible;
//   2. the load-bearing copy (h1, counts, install command, primary CTA) lives
//      in the FIRST stop, which renders with .fr-on and is never hidden.

import { describe, expect, it } from "vitest";
import { readFileSync } from "node:fs";
import { resolve } from "node:path";

const read = (p: string) => readFileSync(resolve(process.cwd(), p), "utf8");

describe("ride crawler visibility", () => {
  it("hides stops only under .fr-live (never in the static fallback)", () => {
    const css = read("app/global.css");
    const hidingRules = css
      .split("\n")
      .filter((line) => /visibility:\s*hidden/.test(line));

    expect(
      hidingRules.length,
      "expected the ride to hide inactive stops via visibility",
    ).toBeGreaterThan(0);

    // Every visibility:hidden in the ride block must sit inside a .fr-live
    // scope. Grab the selector that opens each rule and assert it.
    const liveScoped = css.match(/\.fr-live[^{]*\{[^}]*visibility:\s*hidden/g) ?? [];
    expect(
      liveScoped.length,
      "ride stops must only be hidden under .fr-live, so a failed hydration " +
        "or no-JS client still renders every stop",
    ).toBeGreaterThan(0);
  });

  it("only sets .fr-live after React mounts", () => {
    const src = read("components/world/factory-ride.tsx");
    // The class must come from component state, not be hardcoded on the root.
    expect(src).toMatch(/fr-live/);
    expect(
      /className={`fr-root\s*\$\{live/.test(src) ||
        /live\s*\?\s*"[^"]*fr-live/.test(src) ||
        /classList\.(add|toggle)\("fr-live"/.test(src),
      "fr-live must be applied from the `live` state (set in an effect), " +
        "never rendered unconditionally in the server HTML",
    ).toBe(true);
  });

  it("renders the first stop active so it is visible before any scroll", () => {
    const src = read("components/world/factory-ride.tsx");
    expect(
      /i === 0 \? "fr-stop fr-on" : "fr-stop"/.test(src),
      "the first stop must render with fr-on so its copy is visible " +
        "pre-scroll and to render-then-index crawlers",
    ).toBe(true);
  });

  it("keeps load-bearing hero copy in the first stop", () => {
    const page = read("app/(home)/page.tsx");
    const heroStart = page.indexOf("hero={");
    const cardsStart = page.indexOf("cards={");
    expect(heroStart).toBeGreaterThan(-1);
    expect(cardsStart).toBeGreaterThan(heroStart);

    const heroSlot = page.slice(heroStart, cardsStart);
    for (const needle of [
      'id="hero-heading"', // the h1
      "CopyInstallButton", // install command
      "Get started", // primary CTA
      "COUNTS.skills", // the counts line
    ]) {
      expect(
        heroSlot.includes(needle),
        `${needle} must live in the always-visible first stop, not a later ` +
          "stop that stays visibility:hidden until scrolled",
      ).toBe(true);
    }
  });
});
